import base64import pytzimport pandas as pdimport yfinance as yfimport streamlit as stimport plotly.graph_objects as gofrom PIL import Imagefrom datetime import datetime, timedeltafrom typing import Dict, List# ---------------------------------------------------------# PROJECT IMPORTS & FALLBACKS# ---------------------------------------------------------try:    from src.services.db_service import save_daily_log, get_history_with_validation    from src.engine.forecaster import get_sector_performanceexcept ImportError:    def save_daily_log(*args):        pass    def get_history_with_validation():        return pd.DataFrame()    def get_sector_performance():        return []# ---------------------------------------------------------# CORE UTILITIES# ---------------------------------------------------------def get_base64_image(image_path):    try:        with open(image_path, "rb") as img_file:            return base64.b64encode(img_file.read()).decode()    except Exception:        return ""def clean_symbol(symbol: str) -> str:    return symbol.replace("=F", "").replace("=X", "")@st.cache_data(show_spinner=False)def _get_london_ohlc(symbol: str, date_key: str):    try:        hist = yf.Ticker(symbol).history(period="1d", interval="1h")        data = hist.between_time("03:00", "11:30")        if data.empty: return 0.0, 0.0, 0.0, 0.0        return (float(data["Open"].iloc[0]), float(data["High"].max()),                float(data["Low"].min()), float(data["Close"].iloc[-1]))    except Exception:        return 0.0, 0.0, 0.0, 0.0def _session_timer(now, hour_open, min_open, hour_close, min_close) -> str:    open_t = now.replace(hour=hour_open, minute=min_open, second=0, microsecond=0)    close_t = now.replace(hour=hour_close, minute=min_close, second=0, microsecond=0)    if now < open_t:        diff = int((open_t - now).total_seconds())        return f"Opens in {diff // 3600}h {(diff // 60) % 60}m"    elif now < close_t:        diff = int((close_t - now).total_seconds())        return f"Closes in {diff // 3600}h {(diff // 60) % 60}m"    else:        next_open = open_t + timedelta(days=1)        if next_open.weekday() >= 5: next_open += timedelta(days=(7 - next_open.weekday()))        diff = int((next_open - now).total_seconds())        return f"Opens in {diff // 3600}h {(diff // 60) % 60}m"# ---------------------------------------------------------# 1. HEADER RIBBON# ---------------------------------------------------------def render_header_ribbon(symbol: str, result: Dict):    p1, bias, color = result["p1"], result["bias"], result["color"]    display_symbol = clean_symbol(symbol)    # Encoding Logos    ny_b64 = get_base64_image("src/ui/assets/NyseNasdaqExchangesLogo.jpg")    lon_b64 = get_base64_image("src/ui/assets/LondonStockExchangeLogo.jpg")    globe_color = "#00ff88" if bias == "Bullish" else ("#ff4b4b" if bias == "Bearish" else "#888888")    glow = f"0 0 20px rgba({0 if bias == 'Bullish' else 255}, {255 if bias == 'Bullish' else 75}, {136 if bias == 'Bullish' else 75}, 0.5)"    st.markdown(f"""        <style>        /* Safe spacing fixes */        .block-container {{ padding-top: 2rem !important; }}        /* Session Card Styling */        .session-card {{            border-radius: 12px; padding: 15px; height: 165px;            display: flex; justify-content: space-between;            color: #000000 !important; font-family: sans-serif;        }}        .ny-card {{ background-color: #b3e5fc; }}        .lon-card {{ background-color: #e1bee7; }}        .dark-card {{            background-color: #161a20; border-radius: 12px;            padding: 15px; height: 165px; text-align: center;            border: 1px solid #2d343d; display: flex;            flex-direction: column; justify-content: center;        }}        .neon-bull {{ color: #00ff88 !important; text-shadow: 0 0 12px rgba(0,255,136,0.5); }}        .neon-bear {{ color: #ff4b4b !important; text-shadow: 0 0 12px rgba(255,75,75,0.5); }}        /* Hide default HTML details arrow for custom expander */        details > summary {{ list-style: none; }}        details > summary::-webkit-details-marker {{ display: none; }}        </style>    """, unsafe_allow_html=True)    now_et = datetime.now(pytz.timezone("US/Eastern"))    ny_t, lon_t = _session_timer(now_et, 9, 30, 16, 0), _session_timer(now_et, 3, 0, 11, 30)    ny_open = now_et.replace(hour=9, minute=30) <= now_et < now_et.replace(hour=16, minute=0)    lon_open = now_et.replace(hour=3, minute=0) <= now_et < now_et.replace(hour=11, minute=30)    l_open, l_high, l_low, l_close = _get_london_ohlc(symbol, now_et.strftime("%Y-%m-%d"))    pct = ((p1["current"] - p1["prev_close"]) / p1["prev_close"]) * 100    pct_col = "#008000" if pct > 0 else "#ff0000"    c1, c2, c3, c4 = st.columns([1, 1, 1, 1])    with c1:        st.markdown(f"""<div class="session-card ny-card">            <div style="flex:1;"><img src="data:image/jpeg;base64,{ny_b64}" height="40"><br>                <span>⌛ {ny_t}</span><br>                <span style="font-weight:bold; font-size:18px;">Status: <span style="color:{'#008000' if ny_open else '#ff0000'};">{'Open' if ny_open else 'Closed'}</span></span>            </div>            <div style="text-align:right; font-weight:bold; font-size:17px; line-height:1.4;">                Prev: ${p1['prev_close']:.2f}<br>Curr: <span style="color:{pct_col};">${p1['current']:.2f}</span><br>                High: ${p1['high']:.2f}<br>Low: ${p1['low']:.2f}            </div>        </div>""", unsafe_allow_html=True)    with c2:        st.markdown(f"""<div class="session-card lon-card">            <div style="flex:1;"><img src="data:image/jpeg;base64,{lon_b64}" height="40"><br>                <span>⌛ {lon_t}</span><br>                <span style="font-weight:bold; font-size:18px;">Status: <span style="color:{'#008000' if lon_open else '#ff0000'};">{'Open' if lon_open else 'Closed'}</span></span>            </div>            <div style="text-align:right; font-weight:bold; font-size:17px; line-height:1.4;">                Open: ${l_open:.2f}<br>High: ${l_high:.2f}<br>Low: ${l_low:.2f}<br>Close: ${l_close:.2f}            </div>        </div>""", unsafe_allow_html=True)    with c3:        st.markdown(f"""<div class="dark-card" style="box-shadow:{glow}; border-left:8px solid {color};">            <div style="color:#888; font-size:16px; font-weight:bold;">💡 {display_symbol} FORECAST RANGE</div>            <div style="font-size:24px; font-weight:900; margin:8px 0;">                <span style="color:#ff4b4b;">${p1['downside']:.2f}</span> — <span style="color:#00ff88;">${p1['upside']:.2f}</span>            </div>            <div style="font-size:14px; font-weight:bold;">VOL RATIO: <span style="color:white;">{p1['vol_ratio']:.2f}x</span></div>        </div>""", unsafe_allow_html=True)    with c4:        st.markdown(f"""<div class="dark-card" style="box-shadow:{glow};">            <div style="color:#888; font-size:16px; font-weight:bold; text-transform:uppercase; margin-bottom:5px;">Market Bias</div>            <div style="width: 45px; height: 45px; border-radius: 50%; margin: 0 auto 5px auto; background: radial-gradient(circle at 30% 30%, {globe_color}, #000); box-shadow: 0 0 15px {globe_color};"></div>            <div class="{'neon-bull' if bias == 'Bullish' else 'neon-bear'}" style="font-size:28px; font-weight:900;">{bias}</div>        </div>""", unsafe_allow_html=True)# ---------------------------------------------------------# 2. ROW ONE (Native Containers used to fix Ghost Boxes)# ---------------------------------------------------------def render_row_one(symbol: str, result: Dict):    st.markdown("<br>", unsafe_allow_html=True)  # Replaces old margin gap safely    p1, score, bias, color = result["p1"], result["score"], result["bias"], result["color"]    t_pts, s_pts, mood = result["t_pts"], result["s_pts"], result["market_mood"]    g_color = "#00ff88" if bias == "Bullish" else ("#ff4b4b" if bias == "Bearish" else "#888888")    c1, c2, c3, c4 = st.columns([1, 1.2, 1, 1])    with c1:        with st.container(border=True):  # Native Streamlit bordered card            st.markdown(f"""<h3 style="margin-top:0; display:flex; align-items:center; gap:8px;">                <div style="background: radial-gradient(circle at 30% 30%, {g_color}, #000); box-shadow: 0 0 8px {g_color}; width:20px; height:20px; border-radius:50%; flex-shrink:0;"></div>                Conviction: <span style="color:{color}; margin-left:5px;">{bias}</span>            </h3>""", unsafe_allow_html=True)            fig = go.Figure(go.Indicator(mode="gauge+number", value=score, gauge={"bar": {"color": color}}))            fig.update_layout(height=160, margin=dict(l=10, r=10, t=30, b=0), paper_bgcolor="rgba(0,0,0,0)",                              font={"color": "white"})            st.plotly_chart(fig, use_container_width=True)            st.metric("Market Mood Score", mood)    with c2:        with st.container(border=True):            st.subheader("Forecast Breakdown")            fig = go.Figure(go.Bar(x=[t_pts, s_pts], y=["Price", "News"], orientation="h", marker_color=color,                                   text=[f"{t_pts:.2f}", f"{s_pts:.2f}"], textposition="auto"))            fig.update_layout(height=210, paper_bgcolor="rgba(0,0,0,0)", font={"color": "white"},                              margin=dict(l=5, r=5, t=5, b=5))            st.plotly_chart(fig, use_container_width=True)    with c3:        with st.container(border=True):            st.subheader("📊 Volume Trend")            st.metric("Momentum", f"{p1['vol_ratio']:.2f}x", f"{round((p1['vol_ratio'] - 1) * 100, 1)}%")            fig = go.Figure(go.Scatter(y=[0.8, 1.1, 0.9, p1["vol_ratio"]], fill="tozeroy", line=dict(color="#00cc66")))            fig.update_layout(height=130, margin=dict(l=0, r=0, t=0, b=0), xaxis_visible=False, yaxis_visible=False,                              paper_bgcolor="rgba(0,0,0,0)")            st.plotly_chart(fig, use_container_width=True)    with c4:        with st.container(border=True):            st.subheader("💪 Relative Strength")            try:                nq = yf.Ticker("NQ=F").history(period="1d")                strength = ((nq["Close"].iloc[-1] / nq["Open"].iloc[0])) * 100                st.metric("NQ vs Group", f"{strength:.1f}", "Strong" if strength > 100 else "Weak")                fig = go.Figure(go.Indicator(mode="gauge+number", value=strength, gauge={"axis": {"range": [98, 102]},                                                                                         "bar": {                                                                                             "color": "#00cc66" if strength > 100 else "#ff4b4b"}}))                fig.update_layout(height=130, margin=dict(l=10, r=10, t=0, b=0), paper_bgcolor="rgba(0,0,0,0)",                                  font={"color": "white"})                st.plotly_chart(fig, use_container_width=True)            except:                st.warning("Loading...")# ---------------------------------------------------------# 3. ROW TWO & NEWS PANEL (Custom HTML Expander)# ---------------------------------------------------------def render_row_two(symbol: str, result: Dict):    c1, c2 = st.columns([1.5, 1])    with c1:        st.subheader("📜 History")        hist_df = get_history_with_validation()        st.dataframe(hist_df, height=250, use_container_width=True)    with c2:        st.subheader("🌍 Sector Trend")        sec_data = get_sector_performance()        if sec_data:            cols = st.columns(len(sec_data))            for i, s in enumerate(sec_data):                s_c = "#00cc66" if s["change"] > 0 else "#ff4b4b"                cols[i].markdown(f"""<div style="background-color:#1e1e1e; border-top:5px solid {s_c}; padding:15px 5px; text-align:center; border-radius:8px;">                    <p style="margin:0; font-size:14px; color:white; font-weight:bold;">{s['sector']}</p>                    <p style="margin:0; font-size:18px; color:{s_c}; font-weight:bold;">{s['change']:.2f}%</p></div>""",                                 unsafe_allow_html=True)def render_news_panel(news):    st.subheader("📰 Market Intel")    for idx, n in enumerate(news):        s_color = n.get('sentiment_color', '#cccccc')        # 10% opacity tint using 8-character hex (1A = ~10% opacity)        bg_tint = f"{s_color}1A" if len(s_color) == 7 else "rgba(255,255,255,0.05)"        # Pure HTML Expander (<details> tag) to allow inline globes and hyperlinks        st.markdown(f"""            <details style="border-left: 5px solid {s_color}; background-color: {bg_tint}; padding: 12px 15px; border-radius: 6px; margin-bottom: 12px; cursor: pointer;">                <summary style="display: flex; align-items: center; gap: 12px; font-weight: bold; outline: none;">                    <div style="background: radial-gradient(circle at 30% 30%, {s_color}, #000); box-shadow: 0 0 8px {s_color}; width: 18px; height: 18px; border-radius: 50%; flex-shrink: 0;"></div>                    <a href="{n.get('url', '#')}" target="_blank" style="color: #4da3ff; text-decoration: none; font-size: 1.15rem;">{n.get('title', 'No Title')}</a>                </summary>                <div style="color: #cccccc; font-size: 0.95rem; padding-left: 30px; margin-top: 10px;">                    Source: <strong>{n.get('source', 'Unknown')}</strong> | Published: {n.get('time', 'N/A')}                </div>            </details>        """, unsafe_allow_html=True)